  <script>
  const WA_NUMBER = '51932363832';
  const WA_LINK   = 'https://wa.me/<?= $waNum ?>';
  const PROMO_SECTIONS = ['Burgers', 'Pollos Crispy'];

  let carrito = {};   // id -> { nombre, precio, qty }
  let carritoMobileOpen = false;
  const _prods = {};

  // ── RENDER CARTA ──
  function badgeHTML(badge) {
    if (!badge || badge === 'ninguno') return '';
    return `<span class="item-badge ${badge}">${badge}</span>`;
  }

  function fotoHTML(foto, prodId) {
    const src = foto ? (foto.startsWith('img/') ? '../' + foto : foto) : null;
    const img = src
      ? `<img class="item-foto" src="${src}" alt="" loading="lazy">`
      : `<div class="item-foto" style="display:flex;align-items:center;justify-content:center;background:#2a2a2a"><svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="#555" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M4 6h16" stroke-width="2.5" stroke-linecap="round"/><path d="M4 10h16"/><path d="M4 14h16"/><path d="M6 18h12a2 2 0 0 0 2-2v0a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v0a2 2 0 0 0 2 2z"/><path d="M5 6a7 7 0 0 1 14 0"/></svg></div>`;
    return `<div class="item-foto-wrap">${img}<span class="foto-qty-badge" id="foto-badge-p${prodId}"></span></div>`;
  }

  function getTotalProductQty(prodId) {
    const prefix = 'p' + prodId;
    return Object.entries(carrito)
      .filter(([k]) => k === prefix || k.startsWith(prefix + '_'))
      .reduce((sum, [, v]) => sum + (v.qty || 0), 0);
  }

  function buildItem(p) {
    _prods[p.id] = p;
    const id = 'p' + p.id;
    const qty = getTotalProductQty(p.id);
    const tieneVariantes = p.variantes && p.variantes.length > 0;

    if (tieneVariantes) {
      const minPrecio = Math.min(...p.variantes.map(v => parseFloat(v.precio)));
      return `<div class="item" onclick="openDetail(${p.id})">
        ${fotoHTML(p.foto, p.id)}
        <div class="item-info">
          ${badgeHTML(p.badge)}
          <div class="item-name">${p.nombre}</div>
          ${p.descripcion ? `<div class="item-desc">${p.descripcion}</div>` : ''}
          <div class="item-price">Desde S/${Math.round(minPrecio)}</div>
        </div>
        <div class="item-right">
          <div class="qty-ctrl" onclick="event.stopPropagation()">
            <button class="qty-btn ${qty > 0 ? 'has-items' : ''}" onclick="cambiarCombo('${id}',-1)" aria-label="Quitar">−</button>
            <span class="qty-num" id="qty-${id}">${qty > 0 ? qty : ''}</span>
            <button class="qty-btn ${qty > 0 ? 'has-items' : ''}" onclick="openDetail(${p.id})" aria-label="Agregar">+</button>
          </div>
        </div>
      </div>`;
    }

    return `<div class="item" onclick="openDetail(${p.id})">
      ${fotoHTML(p.foto, p.id)}
      <div class="item-info">
        ${badgeHTML(p.badge)}
        <div class="item-name">${p.nombre}</div>
        ${p.descripcion ? `<div class="item-desc">${p.descripcion}</div>` : ''}
        <div class="item-price">S/${Math.round(p.precio)}</div>
      </div>
      <div class="item-right">
        <div class="qty-ctrl" onclick="event.stopPropagation()">
          <button class="qty-btn ${qty > 0 ? 'has-items' : ''}" onclick="cambiarCombo('${id}',-1)" aria-label="Quitar">−</button>
          <span class="qty-num" id="qty-${id}">${qty > 0 ? qty : ''}</span>
          <button class="qty-btn ${qty > 0 ? 'has-items' : ''}" onclick="openDetail(${p.id})" aria-label="Agregar">+</button>
        </div>
      </div>
    </div>`;
  }

  function buildSeccion(sec) {
    const prods = (sec.productos || []).filter(p => p.activo == 1);
    const titulo = sec.subtitulo ? sec.nombre + ' — ' + sec.subtitulo : sec.nombre;
    const itemsHTML = prods.map(p => buildItem(p)).join('');
    let html = `<div class="section" id="sec-${sec.id}"><div class="section-title">${titulo}</div><div class="section-body">${itemsHTML}</div></div>`;
    if (PROMO_SECTIONS.includes(sec.nombre)) {
      html += `<div class="promo-bar">Adicionales: <span>Dobla tu burger S/8</span> &nbsp;&middot;&nbsp; <span>Queso y tocino a las papas S/6</span></div>`;
    }
    return html;
  }


  function buildCategoryPills(secciones) {
    const bar = document.getElementById('cat-pills');
    if (!bar || !secciones.length) return;
    bar.innerHTML = secciones.map((s, i) =>
      `<button class="cat-pill${i === 0 ? ' active' : ''}" onclick="scrollToSeccion('sec-${s.id}')">${s.nombre}</button>`
    ).join('');
    const pills = [...bar.querySelectorAll('.cat-pill')];
    const io = new IntersectionObserver(entries => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          const idx = secciones.findIndex(s => 'sec-' + s.id === e.target.id);
          if (idx >= 0) {
            pills.forEach(p => p.classList.remove('active'));
            if (pills[idx]) {
              pills[idx].classList.add('active');
              pills[idx].scrollIntoView({ inline: 'nearest', block: 'nearest' });
            }
          }
        }
      });
    }, { rootMargin: '-15% 0px -75% 0px' });
    secciones.forEach(s => { const el = document.getElementById('sec-' + s.id); if (el) io.observe(el); });
    const _sb = document.getElementById('search-bar');
    if (_sb) {
      const _hh = (document.querySelector('header') || {}).offsetHeight || 64;
      const _bh = (document.getElementById('category-bar') || {}).offsetHeight || 48;
      _sb.style.top = (_hh + _bh) + 'px';
    }
  }

  function scrollToSeccion(id) {
    const el = document.getElementById(id);
    if (!el) return;
    const hdr = document.querySelector('header')?.offsetHeight || 56;
    const bar = document.getElementById('category-bar')?.offsetHeight || 48;
    const srch = document.getElementById('search-bar')?.offsetHeight || 0;
    window.scrollTo({ top: el.getBoundingClientRect().top + window.scrollY - hdr - bar - srch - 8, behavior: 'smooth' });
  }


  let _searchTrackT = null;
  function filtrarProductos(q) {
    const query = (q || '').toLowerCase().trim();
    if (window.track) {
      clearTimeout(_searchTrackT);
      _searchTrackT = setTimeout(function () {
        if (query.length >= 3) track('search', 'carta', { ubicacion_id: CARTA_ID, meta: { term: query } });
      }, 900);
    }
    document.querySelectorAll('.section').forEach(sec => {
      let any = false;
      sec.querySelectorAll('.item:not(.item-parent):not(.item-variant), .item-variant').forEach(item => {
        const name = (item.querySelector('.item-name,.item-variant-name')?.textContent || '').toLowerCase();
        const desc = (item.querySelector('.item-desc')?.textContent || '').toLowerCase();
        const show = !query || name.includes(query) || desc.includes(query);
        item.style.display = show ? '' : 'none';
        if (show) any = true;
      });
      sec.querySelectorAll('.item-parent').forEach(p => { p.style.display = any ? '' : 'none'; });
      sec.style.display = any ? '' : 'none';
    });
  }

  const CARTA_ID = <?= (int)$ubiId ?>;
  const SALES_MODE = '<?= $salesMode ?>';
  const IZ_ENABLED = <?= $izEnabled ? 'true' : 'false' ?>;
  const OPEN_H = <?= (int)($ubi['hora_apertura'] ?? 0) ?>, CLOSE_H = <?= (int)($ubi['hora_cierre'] ?? 0) ?>;
  const CERRADO_MANUAL = <?= !empty($ubi['cerrado_manual']) ? 'true' : 'false' ?>;
  function isStoreOpen() {
    if (CERRADO_MANUAL) return false;
    if (OPEN_H === CLOSE_H) return true;            // sin horario configurado => sin restricción
    const h = new Date().getHours();
    return CLOSE_H > OPEN_H ? (h >= OPEN_H && h < CLOSE_H) : (h >= OPEN_H || h < CLOSE_H);
  }
  function reflectStoreState(open) { document.body.classList.toggle('tienda-cerrada', !open); }
  let _cerradoToastT = null;
  function avisoCerrado() {
    let t = document.getElementById('cerrado-toast');
    if (!t) {
      t = document.createElement('div'); t.id = 'cerrado-toast';
      t.innerHTML = '<span class="ct-dot"></span> Estamos cerrados en este momento';
      document.body.appendChild(t);
    }
    requestAnimationFrame(() => t.classList.add('show'));
    clearTimeout(_cerradoToastT);
    _cerradoToastT = setTimeout(() => t.classList.remove('show'), 3200);
  }
  const ANALYTICS_VERSION = 'pedidos';
  const ANALYTICS_API = '<?= APP_URL ?>/api/';


  async function loadCarta() {
    try {
      const res = await fetch('<?= APP_URL ?>/api/carta.php?ubicacion_id=' + CARTA_ID);
      const data = await res.json();
      const secciones = (data.secciones || []).filter(s => s.activo == 1);
      document.getElementById('loading').style.display = 'none';
      document.getElementById('carta-content').innerHTML = secciones.map(buildSeccion).join('');
      buildCategoryPills(secciones);

    } catch(e) {
      document.getElementById('loading').innerHTML = '<p style="color:#e53935;text-align:center">Error cargando la carta. Recarga la página.</p>';
    }
  }

  function cambiarCombo(id, delta) {
  // Find all combo keys for this product
  const comboKeys = Object.keys(carrito).filter(k => k === id || k.startsWith(id + '_'));
  if (delta < 0 && comboKeys.length > 0) {
    // Remove one from the last added combo
    const lastKey = comboKeys[comboKeys.length - 1];
    carrito[lastKey].qty += delta;
    if (carrito[lastKey].qty <= 0) delete carrito[lastKey];
  }
  // Update display
  const totalCombo = Object.entries(carrito).filter(([k]) => k === id || k.startsWith(id + '_')).reduce((s,[,v]) => s + v.qty, 0);
  const el = document.getElementById('qty-' + id);
  if (el) {
    el.textContent = totalCombo;
    el.parentElement.querySelectorAll('.qty-btn').forEach(b => b.classList.toggle('has-items', totalCombo > 0));
  }
  actualizarCarrito();
}

function cambiar(id, nombre, precio, delta) {
    if (!carrito[id]) carrito[id] = { nombre, precio, qty: 0 };
    carrito[id].qty = Math.max(0, carrito[id].qty + delta);
    if (carrito[id].qty === 0) delete carrito[id];
    if (delta > 0 && window.track) track('add_to_cart', 'carta', { ubicacion_id: CARTA_ID, meta: { product_id: id, nombre: nombre } });

    // Update qty display
    const el = document.getElementById('qty-' + id);
    if (el) {
      const qty = carrito[id] ? carrito[id].qty : 0;
      el.textContent = qty;
      // Update button states
      el.parentElement.querySelectorAll('.qty-btn').forEach(btn => {
        btn.classList.toggle('has-items', qty > 0);
      });
    }

    actualizarCarrito();
  }

  function actualizarCarrito() {
    let total = 0, count = 0;
    const items = [];
    for (const [id, item] of Object.entries(carrito)) {
      total += item.precio * item.qty;
      count += item.qty;
      items.push(item);
    }

    // Update foto badges + in-cart state
    Object.keys(_prods).forEach(prodId => {
      const qty = getTotalProductQty(prodId);
      const badge = document.getElementById('foto-badge-p' + prodId);
      if (badge) { badge.textContent = qty > 0 ? qty : ''; badge.style.display = qty > 0 ? 'flex' : 'none'; }
      document.querySelectorAll(`.item[onclick="openDetail(${prodId})"],.item-parent[onclick="openDetail(${prodId})"]`).forEach(el => el.classList.toggle('in-cart', qty > 0));
    });

    // MOBILE
    const mob = document.getElementById('carrito-mobile');
    if (count === 0) {
      mob.classList.remove('visible');
    } else {
      mob.classList.add('visible');
      document.getElementById('mobile-badge').textContent = count;
      document.getElementById('mobile-total').textContent = 'S/' + Math.round(total);
      document.getElementById('mobile-items').innerHTML = items.map(i =>
        `<div class="carrito-item-row">
          <span class="carrito-item-name">${i.qty}x ${i.nombre}</span>
          <span class="carrito-item-price">S/${Math.round(i.precio * i.qty)}</span>
        </div>`
      ).join('');
    }

    // DESKTOP
    const dEmpty = document.getElementById('desktop-empty');
    const dItems = document.getElementById('desktop-items');
    const dTotal = document.getElementById('desktop-total');
    const dWA    = document.getElementById('desktop-wa-btn');
    const dVac   = document.getElementById('desktop-vaciar-btn');
    const dBadge = document.getElementById('desktop-badge');

    if (count === 0) {
      dEmpty.style.display = 'block';
      dItems.innerHTML = '';
      dTotal.style.display = 'none';
      dWA.style.display = 'none';
      dVac.style.display = 'none';
      dBadge.style.display = 'none';
    } else {
      dEmpty.style.display = 'none';
      dBadge.style.display = 'inline';
      dBadge.textContent = count;
      dItems.innerHTML = items.map(i =>
        `<div class="carrito-desktop-row">
          <span class="carrito-desktop-name">${i.qty}x ${i.nombre}</span>
          <span class="carrito-desktop-price">S/${Math.round(i.precio * i.qty)}</span>
        </div>`
      ).join('');
      document.getElementById('desktop-total-val').textContent = 'S/' + Math.round(total);
      dTotal.style.display = 'flex';
      dWA.style.display = 'flex';
      dVac.style.display = 'block';
    }

    // Refresh product-level qty counters in cards
    const _allPids = new Set(
      Object.keys(carrito).map(k => { const m = k.match(/^p(\d+)/); return m ? m[1] : null; }).filter(Boolean)
    );
    document.querySelectorAll('.qty-num[id^="qty-p"]').forEach(el => {
      const pid = el.id.replace('qty-p', '');
      const total = getTotalProductQty(pid);
      el.textContent = total > 0 ? total : '';
      const ctrl = el.closest('.qty-ctrl');
      if (ctrl) ctrl.querySelectorAll('.qty-btn').forEach(b => b.classList.toggle('has-items', total > 0));
    });
  }

  function toggleCarritoMobile() {
    carritoMobileOpen = !carritoMobileOpen;
    document.getElementById('mobile-items-wrap').classList.toggle('open', carritoMobileOpen);
  }

  function vaciarCarrito() {
    carrito = {};
    // Reset all qty displays
    document.querySelectorAll('.qty-num').forEach(el => el.textContent = '0');
    document.querySelectorAll('.qty-btn').forEach(btn => btn.classList.remove('has-items'));
    actualizarCarrito();
    carritoMobileOpen = false;
    document.getElementById('mobile-items-wrap').classList.remove('open');
