  let tipoEntrega = 'delivery';
  let loyaltyOpcion = 'nueva'; // 'no' | 'nueva' | 'tengo'

  function setLoyalty(opcion) {
    loyaltyOpcion = opcion;
    const opts = ['no', 'nueva', 'tengo'];
    opts.forEach(o => {
      const btn   = document.getElementById('loyalty-opt-' + o);
      const radio = document.getElementById('loyalty-radio-' + o);
      const isActive = o === opcion;
      btn.style.borderColor   = isActive ? '#F5C200' : '#ddd';
      btn.style.background    = isActive ? '#fffbec' : '#fff';
      radio.style.borderColor = isActive ? '#F5C200' : '#ddd';
      radio.style.background  = isActive ? '#F5C200' : '#fff';
      radio.querySelector('div').style.background = isActive ? '#1B1F4B' : 'transparent';
    });
    // Show email field for 'nueva' and 'tengo'
    document.getElementById('loyalty-email-wrap').style.display = opcion !== 'no' ? 'block' : 'none';
    // Update placeholder based on option
    const emailInput = document.getElementById('campo-loyalty-email');
    if (emailInput) {
      emailInput.placeholder = opcion === 'tengo' ? 'Email de tu tarjeta existente' : 'tu@correo.com';
    }
  }

  let _codigoActual = '';
  let _emailLealtadActual = '';

  function copiarCodigo() {
    const codigo = document.getElementById('codigo-display').textContent;
    const emailLeal = _emailLealtadActual;
    const texto = emailLeal ? `${codigo} · ${emailLeal}` : codigo;
    const btn = document.getElementById('btn-copiar');
    const doCopy = () => {
      btn.textContent = '¡Copiado!';
      btn.style.background = '#25D366';
      btn.style.color = '#fff';
      setTimeout(() => {
        btn.textContent = 'Copiar código';
        btn.style.background = '#F5C200';
        btn.style.color = '#1B1F4B';
      }, 2000);
    };
    if (navigator.clipboard) {
      navigator.clipboard.writeText(texto).then(doCopy).catch(() => {
        const el = document.createElement('textarea');
        el.value = texto; document.body.appendChild(el); el.select();
        document.execCommand('copy'); document.body.removeChild(el); doCopy();
      });
    } else {
      const el = document.createElement('textarea');
      el.value = texto; document.body.appendChild(el); el.select();
      document.execCommand('copy'); document.body.removeChild(el); doCopy();
    }
  }

  function cerrarModalCodigo() {
    document.getElementById('modal-codigo').style.display = 'none';
    window._emailYaExistia = false;
    vaciarCarrito();
  }

  function enviarPedido() {
    const items = Object.values(carrito);
    if (!items.length) return;
    if (!isStoreOpen()) { avisoCerrado(); return; }
    poblarHorarios();
    setLoyalty('no');   // GringoLovers oculto por ahora
    document.getElementById('modal-pedido').style.display = 'flex';
    document.body.style.overflow = 'hidden';
    if (window.track) track('checkout_open', 'carta', { ubicacion_id: CARTA_ID, meta: { items: Object.keys(carrito).length } });
  }

  function poblarHorarios() {
    const select = document.getElementById('campo-horario');
    while (select.options.length > 1) select.remove(1);
    const now = new Date();
    const cur = now.getHours() * 60 + now.getMinutes();
    for (let m = 18*60; m < 24*60; m += 30) {
      if (m > cur + 15) {
        const h = Math.floor(m/60), mn = m%60;
        const lbl = h.toString().padStart(2,'0') + ':' + mn.toString().padStart(2,'0');
        const opt = document.createElement('option');
        opt.value = lbl; opt.textContent = lbl;
        select.appendChild(opt);
      }
    }
  }

  function setTipoEntrega(tipo) {
    tipoEntrega = tipo;
    const isD = tipo === 'delivery';
    const dBtn = document.getElementById('opt-delivery');
    const rBtn = document.getElementById('opt-recojo');
    const dRad = document.getElementById('radio-delivery');
    const rRad = document.getElementById('radio-recojo');
    dBtn.style.borderColor = isD ? '#F5C200' : '#ddd';
    dBtn.style.background  = isD ? '#fffbec' : '#fff';
    rBtn.style.borderColor = !isD ? '#F5C200' : '#ddd';
    rBtn.style.background  = !isD ? '#fffbec' : '#fff';
    dRad.style.borderColor = isD ? '#F5C200' : '#ddd';
    dRad.style.background  = isD ? '#F5C200' : '#fff';
    dRad.querySelector('div').style.background = isD ? '#1B1F4B' : 'transparent';
    rRad.style.borderColor = !isD ? '#F5C200' : '#ddd';
    rRad.style.background  = !isD ? '#F5C200' : '#fff';
    rRad.querySelector('div').style.background = !isD ? '#1B1F4B' : 'transparent';
