  }

  function cerrarModal() {
    document.getElementById('modal-pedido').style.display = 'none';
    document.body.style.overflow = '';
  }

  function confirmarPedido() {
    if (!isStoreOpen()) { cerrarModal(); avisoCerrado(); return; }
    let valid = true;
    const nombre   = document.getElementById('campo-nombre').value.trim();
    const telefono = document.getElementById('campo-telefono').value.trim();
    const direccion = tipoEntrega === 'delivery' ? document.getElementById('campo-direccion').value.trim() : '';

    if (!nombre) {
      document.getElementById('err-nombre').style.display = 'block';
      document.getElementById('campo-nombre').style.borderColor = '#dc2626';
      valid = false;
    } else {
      document.getElementById('err-nombre').style.display = 'none';
      document.getElementById('campo-nombre').style.borderColor = '#ddd';
    }
    if (!telefono) {
      document.getElementById('err-telefono').style.display = 'block';
      document.getElementById('campo-telefono').style.borderColor = '#dc2626';
      valid = false;
    } else {
      document.getElementById('err-telefono').style.display = 'none';
      document.getElementById('campo-telefono').style.borderColor = '#ddd';
    }
    if (tipoEntrega === 'delivery' && !direccion) {
      document.getElementById('err-direccion').style.display = 'block';
      document.getElementById('campo-direccion').style.borderColor = '#dc2626';
      valid = false;
    } else {
      document.getElementById('err-direccion').style.display = 'none';
      if (document.getElementById('campo-direccion'))
        document.getElementById('campo-direccion').style.borderColor = '#ddd';
    }
    if (!valid) return;

    const horario = document.getElementById('campo-horario').value;
    const horarioLabel = horario === 'asap' ? 'Lo antes posible' : horario;
    const comentarios = document.getElementById('campo-comentarios').value.trim();

    const loyaltyEmailWA = document.getElementById('campo-loyalty-email')?.value.trim().toLowerCase() || '';
    const lines = [
      '🍔 *Hola! Quiero hacer un pedido:*', '',
      `*Nombre:* ${nombre}`,
      `*Teléfono:* ${telefono}`,
      tipoEntrega === 'delivery' ? `*Dirección:* ${direccion}` : `*Entrega:* Recojo en local`,
      // HORARIO DESACTIVADO: `*Horario:* ${horarioLabel}`,
    ];
    if (loyaltyEmailWA && loyaltyOpcion !== 'no') lines.push(`*Email lealtad:* ${loyaltyEmailWA}`);
    if (comentarios) lines.push(`*Comentarios:* ${comentarios}`);
    lines.push('', '*Pedido:*');
    const items = Object.values(carrito);
    let total = 0;
    items.forEach(i => {
      const sub = Math.round(i.precio * i.qty);
      total += sub;
      lines.push(`• ${i.qty}x ${i.nombre} — S/${sub}`);
    });
    lines.push('', `*TOTAL: S/${Math.round(total)}*`);
    const msg = encodeURIComponent(lines.join('\n'));

    // Handle loyalty card
    const loyaltyEmail = document.getElementById('campo-loyalty-email')?.value.trim().toLowerCase() || '';
    if (loyaltyOpcion !== 'no') {
      if (!loyaltyEmail || !loyaltyEmail.includes('@')) {
        document.getElementById('err-loyalty-email').style.display = 'block';
        document.getElementById('campo-loyalty-email').style.borderColor = '#dc2626';
        return;
      }
      document.getElementById('err-loyalty-email').style.display = 'none';
      document.getElementById('campo-loyalty-email').style.borderColor = '#ddd';
    }

    // ── IZIPAY: cobrar con tarjeta ANTES de registrar el pedido ──
    if (SALES_MODE === 'izipay') {
      if (!IZ_ENABLED) { alert('El pago con tarjeta no está disponible en este momento. Intenta más tarde.'); return; }
      let izTotal = 0;
      const izItems = Object.entries(carrito).map(([cid, i]) => {
        const sub = Math.round(i.precio * i.qty); izTotal += sub;
        const pid = parseInt((String(cid).match(/^p(\d+)/) || [])[1]) || 0;
        return { product_id: pid, nombre: i.nombre, precio: i.precio, qty: i.qty, subtotal: sub, modificadores: i.mods || [] };
      });
      const loyaltyEmailIz = document.getElementById('campo-loyalty-email')?.value.trim().toLowerCase() || '';
      _pedidoData = {
        nombre, telefono,
        tipo_entrega: tipoEntrega,
        direccion: tipoEntrega === 'delivery' ? direccion : '',
        horario: horarioLabel, comentarios,
        items: izItems, total: Math.round(izTotal),
        carta_id: CARTA_ID, ubicacion_id: CARTA_ID,
        loyaltyEmail: loyaltyEmailIz
      };
      cerrarModal();
      iniciarPago();
      return;
    }

    // Save order to database (fire and forget)
    let saveTotal = 0;
    const itemsData = Object.entries(carrito).map(([cid, i]) => {
      const sub = Math.round(i.precio * i.qty);
      saveTotal += sub;
      const pid = parseInt((String(cid).match(/^p(\d+)/) || [])[1]) || 0;
      return { product_id: pid, nombre: i.nombre, precio: i.precio, qty: i.qty, subtotal: sub, modificadores: i.mods || [] };
    });
    fetch('<?= APP_URL ?>/api/pedido.php', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        nombre, telefono,
        tipo_entrega: tipoEntrega,
        direccion: tipoEntrega === 'delivery' ? direccion : '',
        horario: horarioLabel,
        comentarios,
        items: itemsData,
        total: Math.round(saveTotal),
        carta_id: CARTA_ID || 1,
        ubicacion_id: CARTA_ID || 1
      })
    }).then(r => r.json()).then(d => {
      if (!d.ok) console.error('save_pedido error:', d.error);
    }).catch(e => console.error('save_pedido fetch error:', e));

    cerrarModal();
    if (window.track) track('order_placed', 'carta', { ubicacion_id: CARTA_ID, meta: { metodo: 'whatsapp', total: Math.round(saveTotal) } });
    var _waUrl = 'https://wa.me/<?= $waNum ?>?text=' + msg;
    var _w = window.open(_waUrl, '_blank');
    if (!_w) window.location.href = _waUrl;   // si el navegador bloquea la pestaña nueva, navega en la misma

    // Handle loyalty + generate code
    const loyaltyEmailVal = document.getElementById('campo-loyalty-email')?.value.trim().toLowerCase() || '';
    handleLoyalty(loyaltyEmailVal, nombre);
  }

  async function handleLoyalty(loyaltyEmail, nombre) {
    _emailLealtadActual = loyaltyEmail || '';
    try {
      if (loyaltyOpcion === 'no') return;

      // Create tarjeta if new
      if (loyaltyOpcion === 'nueva' && loyaltyEmail) {
        // Check if email already has a card
        const checkRes = await fetch('<?= APP_URL ?>/api/lealtad.php', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'check_email', email: loyaltyEmail })
        });
        const checkData = await checkRes.json();
        if (checkData.exists) {
          // Email already exists - flag to show message in code modal
          window._emailYaExistia = true;
        } else {
          window._emailYaExistia = false;
          await fetch('<?= APP_URL ?>/api/lealtad.php', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'crear', nombre, email: loyaltyEmail })
          });
        }
      }

      // Generate code - use email for both nueva and tengo
      if (loyaltyEmail) {
        const res = await fetch('<?= APP_URL ?>/api/lealtad.php', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            action: 'generar_codigo',
            email: loyaltyEmail,
            requiere_email: loyaltyOpcion === 'tengo'
          })
        });
        const data = await res.json();
        if (data.ok) {
          _codigoActual = data.codigo;
          document.getElementById('codigo-display').textContent = data.codigo;
          // Show message if email already had a card
          const msgEl = document.getElementById('codigo-msg-existente');
          if (msgEl) {
            msgEl.style.display = (loyaltyOpcion === 'nueva' && window._emailYaExistia) ? 'block' : 'none';
          }
          document.getElementById('modal-codigo').style.display = 'flex';
        }
      }
    } catch(e) {}
  }

  document.getElementById('modal-pedido').addEventListener('click', function(e) {
    if (e.target === this) cerrarModal();
  });

  // ── SCHEDULE BADGE ──
