    if (!badge) return;
    const open = isStoreOpen();
    badge.className = 'schedule-badge ' + (open ? 'open' : 'closed');
    let txt;
    if (open) {
      const closeLabel = (CLOSE_H % 24 === 0) ? '24:00' : (CLOSE_H + ':00');
      txt = (OPEN_H === CLOSE_H) ? 'Abierto' : ('Abierto · hasta las ' + closeLabel);
    } else {
      txt = CERRADO_MANUAL ? 'Cerrado' : ('Cerrado · abre a las ' + OPEN_H + ':00');
    }
    badge.innerHTML = '<div class="schedule-dot"></div>' + txt;
    reflectStoreState(open);
  }
  updateScheduleBadge();
  setInterval(updateScheduleBadge, 60000);

  /* ── DETAIL MODAL JS ── */
  let _detailId = null;
  let _detailModSels = {};
  let _detailVarianteId = null;
  let _detailCloseTimer = null;

  function openDetail(prodId) {
    const p = _prods[prodId];
    if (!p) return;
    _detailId = prodId;
    _detailModSels = {};
    _detailVarianteId = null;

    const mediaEl = document.getElementById('detail-media');
    const foto = p.foto || null;
    const src = foto ? (foto.startsWith('img/') ? '../' + foto : foto) : null;
    const _liked = localStorage.getItem('like_' + prodId + '_' + CARTA_ID + '_' + ANALYTICS_VERSION) === '1';
    const _hFill = _liked ? '#FCDA13' : 'none'; const _hStroke = _liked ? '#FCDA13' : '#ccc';
    const _photoHTML = src
      ? `<img class="detail-img" src="${src}" alt="${p.nombre.replace(/"/g,'')}" loading="lazy">`
      : `<div class="detail-img-placeholder"><svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="#444" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M4 6h16" stroke-width="2.5" stroke-linecap="round"/><path d="M4 10h16"/><path d="M4 14h16"/><path d="M6 18h12a2 2 0 0 0 2-2v0a2 2 0 0 0-2-2H6a2 2 0 0 0-2 2v0a2 2 0 0 0 2 2z"/><path d="M5 6a7 7 0 0 1 14 0"/></svg></div>`;
    mediaEl.innerHTML = `<div class="detail-media-wrap">${_photoHTML}</div>`;
    fetch(ANALYTICS_API + 'carta_analytics.php', {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'registrar_vista',producto_id:prodId,ubicacion_id:CARTA_ID,version:ANALYTICS_VERSION})}).catch(()=>{});
    fetch(ANALYTICS_API + 'carta_analytics.php?action=get_likes&producto_id=' + prodId + '&ubicacion_id=' + CARTA_ID + '&version=' + ANALYTICS_VERSION).then(r=>r.json()).then(d=>{const el=document.getElementById('heart-count');if(el&&d.total>0)el.textContent=d.total;}).catch(()=>{});

    const badgeEl = document.getElementById('detail-badge-el');
    if (p.badge && p.badge !== 'ninguno') {
      const labels = { popular: '⭐ Popular', nuevo: '🆕 Nuevo', recomendado: '👍 Recomendado' };
      badgeEl.innerHTML = `<span class="detail-modal-badge ${p.badge}">${labels[p.badge] || p.badge}</span>`;
    } else { badgeEl.innerHTML = ''; }

    document.getElementById('detail-modal-name').textContent = p.nombre;

    const priceEl = document.getElementById('detail-price-el');
    if (p.variantes && p.variantes.length > 0) {
      priceEl.innerHTML = `<div class="detail-modal-variants">${p.variantes.map(v =>
        `<div class="detail-modal-variant-row" id="dv-${v.id}" onclick="selectDetailVariante(${v.id},${v.precio})">
          <span class="detail-modal-variant-name">${v.nombre}</span>
          <span class="detail-modal-variant-price">S/${Math.round(v.precio)}</span>
        </div>`).join('')}</div>`;
    } else if (p.precio) {
      priceEl.innerHTML = `<div class="detail-modal-price-single">S/${Math.round(p.precio)}</div>`;
    } else { priceEl.innerHTML = ''; }

    const modsEl = document.getElementById('detail-modifiers');
    const grupos = p.grupos_modificadores || [];
    modsEl.innerHTML = grupos.length > 0
      ? `<div class="mods-section">${grupos.map(buildModGroup).join('')}</div>` : '';

    document.getElementById('detail-modal-desc').textContent = p.descripcion || '';
    updateDetailPrice();
    const _likeWrap = document.getElementById('like-wrap');
    if (_likeWrap) _likeWrap.innerHTML = `<button class="like-btn${_liked ? ' liked' : ''}" id="heart-btn" onclick="toggleLike(${prodId})"><svg width="18" height="18" viewBox="0 0 24 24" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/></svg> Me gusta <span class="like-count-chip" id="heart-count"></span></button>`;

    const overlay = document.getElementById('detail-overlay');
    if (_detailCloseTimer) { clearTimeout(_detailCloseTimer); _detailCloseTimer = null; }
    overlay.style.visibility = 'visible';
    overlay.style.pointerEvents = 'auto';
    document.getElementById('detail-sheet').scrollTop = 0;
    requestAnimationFrame(() => requestAnimationFrame(() => overlay.classList.add('open')));
    document.body.style.overflow = 'hidden';
  }

  function selectDetailVariante(varId, precio) {
    const p = _prods[_detailId];
    if (!p) return;
    _detailVarianteId = varId;
    p.variantes.forEach(v => {
      const el = document.getElementById('dv-' + v.id);
      if (el) el.classList.toggle('selected', v.id == varId);
    });
    updateDetailPrice();
  }

  function buildModGroup(g) {
    const pid = _detailId;
    const opts = (g.modificadores || []).map(m => {
      const extra = parseFloat(m.precio_adicional) > 0
        ? `<span class="mod-option-price">+S/${parseFloat(m.precio_adicional).toFixed(2).replace('.00','')}</span>`
        : '';
      return `<button class="mod-option" id="mo-${pid}-${g.id}-${m.id}"
        onclick="toggleMod(${g.id},${m.id},'${g.tipo}',${parseFloat(m.precio_adicional)||0})">
        <span class="mod-option-name">${m.nombre}</span>${extra}
      </button>`;
    }).join('');
    const countTag = g.tipo === 'multiple' && g.max_opciones
      ? ` <span class="mods-count-tag" id="modcount-${pid}-${g.id}">0 / ${g.max_opciones}</span>`
      : '';
    return `<div class="mods-group-wrap" id="modgroup-${g.id}">
      <div class="mods-group-label">${g.nombre}${g.requerido == 1 ? '<span class="mods-required-tag">Requerido</span>' : ''}${countTag}</div>
      <div class="mods-options">${opts}</div>
    </div>`;
  }

  function toggleMod(grupoId, modId, tipo, precioAdicional) {
    if (!_detailModSels[grupoId]) _detailModSels[grupoId] = {};
    const sel = _detailModSels[grupoId];
    const p = _prods[_detailId];
    if (!p) return;
    const g = (p.grupos_modificadores || []).find(g => g.id == grupoId);
    if (!g) return;
    const pid = _detailId;

    if (tipo === 'unico') {
      g.modificadores.forEach(m => {
        sel[m.id] = false;
        const el = document.getElementById('mo-' + pid + '-' + grupoId + '-' + m.id);
        if (el) el.classList.remove('selected');
      });
      sel[modId] = true;
      const el = document.getElementById('mo-' + pid + '-' + grupoId + '-' + modId);
      if (el) el.classList.add('selected');
    } else {
      const max = g.max_opciones || null;
      const isSelected = !!sel[modId];
      if (!isSelected && max && Object.values(sel).filter(Boolean).length >= max) return;
      sel[modId] = !isSelected;
      const el = document.getElementById('mo-' + pid + '-' + grupoId + '-' + modId);
      if (el) el.classList.toggle('selected', sel[modId]);
      if (max) {
        const count = Object.values(sel).filter(Boolean).length;
        const countEl = document.getElementById('modcount-' + pid + '-' + grupoId);
        if (countEl) countEl.textContent = count + ' / ' + max;
        g.modificadores.forEach(m => {
          const optEl = document.getElementById('mo-' + pid + '-' + grupoId + '-' + m.id);
          if (optEl) optEl.classList.toggle('mod-disabled', count >= max && !sel[m.id]);
        });
      }
    }
    document.getElementById('modgroup-' + grupoId)?.classList.remove('mods-error');
    updateDetailPrice();
  }

  function updateDetailPrice() {
    const p = _prods[_detailId];
    if (!p) return;
    let base = 0;
    if (_detailVarianteId) {
      const v = (p.variantes || []).find(v => v.id == _detailVarianteId);
      base = v ? parseFloat(v.precio) : 0;
    } else if (p.precio) {
      base = parseFloat(p.precio);
    }
    for (const [gid, sels] of Object.entries(_detailModSels)) {
      const g = (p.grupos_modificadores || []).find(g => g.id == gid);
      if (g) {
        Object.entries(sels).forEach(([mid, selected]) => {
          if (selected) {
            const m = (g.modificadores || []).find(m => m.id == mid);
            if (m) base += parseFloat(m.precio_adicional) || 0;
          }
        });
      }
    }
    const totalEl = document.getElementById('detail-total-price');
    if (totalEl) totalEl.textContent = base > 0 ? '— S/' + Math.round(base) : '';
  }

  function addDetailToCart() {
    const p = _prods[_detailId];
    if (!p) return;
    const grupos = p.grupos_modificadores || [];
    for (const g of grupos) {
      if (g.requerido == 1) {
        const sel = _detailModSels[g.id] || {};
        if (!Object.values(sel).some(Boolean)) {
          document.getElementById('modgroup-' + g.id)?.classList.add('mods-error');
          document.getElementById('modgroup-' + g.id)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
          return;
        }
      }
    }
    const modParts = [];
    const modArr = [];
    let modPrice = 0;
    for (const [gid, sels] of Object.entries(_detailModSels)) {
      const g = grupos.find(g => g.id == gid);
      if (g) {
        Object.entries(sels).forEach(([mid, selected]) => {
          if (selected) {
            const m = (g.modificadores || []).find(m => m.id == mid);
            if (m) { modParts.push(m.nombre); modArr.push({ nombre: m.nombre, precio: parseFloat(m.precio_adicional) || 0 }); modPrice += parseFloat(m.precio_adicional) || 0; }
          }
        });
      }
    }
    let cartId, nombre, precio;
    if (_detailVarianteId) {
      const v = (p.variantes || []).find(v => v.id == _detailVarianteId);
      if (!v) return;
      nombre = p.nombre + ' — ' + v.nombre;
      precio = parseFloat(v.precio);
      cartId = 'p' + p.id + '_v' + v.id;
    } else {
      nombre = p.nombre;
      precio = parseFloat(p.precio) || 0;
      cartId = 'p' + p.id;
    }
    if (modParts.length > 0 || modPrice > 0) {
      const modKey = Object.entries(_detailModSels).map(([g, s]) =>
        g + ':' + Object.entries(s).filter(([,v]) => v).map(([k]) => k).sort().join(',')
      ).sort().join('|');
      cartId = cartId + '_m' + _simpleHash(modKey);
      nombre = nombre + ' (' + modParts.join(', ') + ')';
      precio = precio + modPrice;
    }
    cambiar(cartId, nombre, precio, 1);
    if (carrito[cartId]) carrito[cartId].mods = modArr;
    closeDetail();
  }

  const personalizarYAgregar = addDetailToCart;

  function _simpleHash(str) {
    let h = 0;
    for (let i = 0; i < str.length; i++) { h = ((h << 5) - h + str.charCodeAt(i)) | 0; }
    return (h >>> 0).toString(36);
  }


  async function toggleLike(prodId) {
    const key = 'like_' + prodId + '_' + CARTA_ID + '_' + ANALYTICS_VERSION;
    const wasLiked = localStorage.getItem(key) === '1';
    const newLiked = !wasLiked;
    if (newLiked) { localStorage.setItem(key, '1'); } else { localStorage.removeItem(key); }
    const btn = document.getElementById('heart-btn');
    if (btn) {
      btn.classList.toggle('liked', newLiked);
      btn.classList.remove('pop'); void btn.offsetWidth; btn.classList.add('pop');
    }
    try {
      const res = await fetch(ANALYTICS_API + 'carta_analytics.php', {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'toggle_like',producto_id:prodId,ubicacion_id:CARTA_ID,version:ANALYTICS_VERSION,liked:newLiked})});
      const d = await res.json();
      if (d.ok) { const el = document.getElementById('heart-count'); if (el) el.textContent = d.total > 0 ? d.total : ''; }
    } catch(e) {}
  }
  function closeDetail() {
    const overlay = document.getElementById('detail-overlay');
    overlay.classList.remove('open');
    document.body.style.overflow = '';
    _detailCloseTimer = setTimeout(() => {
      overlay.style.visibility = 'hidden';
      overlay.style.pointerEvents = 'none';
    }, 380);
  }

  function handleOverlayClick(e) {
    if (e.target === document.getElementById('detail-overlay')) closeDetail();
  }

  document.addEventListener('keydown', e => { if (e.key === 'Escape') closeDetail(); });

  loadCarta();
  if (window.track) track('page_view', 'carta', { ubicacion_id: CARTA_ID, meta: { sales_mode: SALES_MODE } });

